function whens_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('whens', $selected_id, 'edit')) return false;

	$data = [
		'whens_when1' => Request::val('whens_when1', ''),
		'whens_when2' => Request::val('whens_when2', ''),
		'whens_when3' => time24(Request::val('whens_when3', '')),
		'whens_description' => br2nl(Request::val('whens_description', '')),
		'whens_updated' => parseCode('<%%editingTimestamp%%>', false, true),
	];

	if($data['whens_when1'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'When1 (Frequency)': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	if($data['whens_when2'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'When2 (Sessions)': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	if($data['whens_when3'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'When3 (Specific Time)': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	// get existing values
	$old_data = getRecord('whens', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: whens_before_update
	if(function_exists('whens_before_update')) {
		$args = ['old_data' => $old_data];
		if(!whens_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'whens',
		backtick_keys_once($set),
		['`whens_id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="whens_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('whens', $data['selectedID'], calculated_fields()['whens']);

	// hook: whens_after_update
	if(function_exists('whens_after_update')) {
		if($row = getRecord('whens', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['whens_id'];
		$args = ['old_data' => $old_data];
		if(!whens_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('whens', $selected_id);
}

