			&& !Request::val('Embedded')
		)
			$templateCode = str_replace('<%%DESELECT_BUTTON%%>', '', $templateCode);
		elseif($separateDV)
			$templateCode = str_replace(
				'<%%DESELECT_BUTTON%%>',
				'<button
					type="submit"
					class="btn btn-default ltr"
					id="deselect"
					name="deselect_x"
					value="1"
					onclick="' . $backAction . '"
					title="' . html_attr($Translation['Back']) . '">
						<i class="glyphicon glyphicon-chevron-left"></i> ' .
						$Translation['Back'] .
				'</button>',
				$templateCode
			);
		else
			$templateCode = str_replace('<%%DESELECT_BUTTON%%>', '', $templateCode);
	}

	// set records to read only if user can't insert new records and can't edit current record
	if(!$fieldsAreEditable) {
		$jsReadOnly = '';
		$jsReadOnly .= "\t\$j('#whens_when1').replaceWith('<div class=\"form-control-static\" id=\"whens_when1\">' + (\$j('#whens_when1').val() || '') + '</div>'); \$j('#whens_when1-multi-selection-help').hide();\n";
		$jsReadOnly .= "\t\$j('#whens_when2').replaceWith('<div class=\"form-control-static\" id=\"whens_when2\">' + (\$j('#whens_when2').val() || '') + '</div>'); \$j('#whens_when2-multi-selection-help').hide();\n";
		$jsReadOnly .= "\t\$j('#whens_when3').replaceWith('<div class=\"form-control-static\" id=\"whens_when3\">' + (\$j('#whens_when3').val() || '') + '</div>'); \$j('#whens_when3-multi-selection-help').hide();\n";
		$jsReadOnly .= "\t\$j('#whens_description').replaceWith('<div class=\"form-control-static\" id=\"whens_description\">' + (\$j('#whens_description').val() || '') + '</div>');\n";
		$jsReadOnly .= "\t\$j('.select2-container').hide();\n";

		$noUploads = true;
	} else {
		// temporarily disable form change handler till time and datetime pickers are enabled
		$jsEditable = "\t\$j('form').eq(0).data('already_changed', true);";
		$jsEditable .= "\t\$j('#whens_when3').addClass('always_shown').timepicker({ defaultTime: false, showSeconds: true, showMeridian: true, showInputs: false, disableFocus: true, minuteStep: AppGini.config.timeFieldMinutesStep || 5 });";
		$jsEditable .= "\t\$j('form').eq(0).data('already_changed', false);"; // re-enable form change handler
	}

	// process combos
	$templateCode = str_replace('<%%COMBO(whens_when1)%%>', $combo_whens_when1->HTML, $templateCode);
	$templateCode = str_replace('<%%COMBOTEXT(whens_when1)%%>', $combo_whens_when1->SelectedData, $templateCode);
	$templateCode = str_replace('<%%COMBO(whens_when2)%%>', $combo_whens_when2->HTML, $templateCode);
	$templateCode = str_replace('<%%COMBOTEXT(whens_when2)%%>', $combo_whens_when2->SelectedData, $templateCode);
	$templateCode = str_replace('<%%COMBO(whens_when3)%%>', $combo_whens_when3->HTML, $templateCode);
	$templateCode = str_replace('<%%COMBOTEXT(whens_when3)%%>', $combo_whens_when3->SelectedData, $templateCode);

	/* lookup fields array: 'lookup field name' => ['parent table name', 'lookup field caption'] */
	$lookup_fields = [];
	foreach($lookup_fields as $luf => $ptfc) {
		$pt_perm = getTablePermissions($ptfc[0]);

		// process foreign key links
		if(($pt_perm['view'] && isDetailViewEnabled($ptfc[0])) || $pt_perm['edit']) {
			$templateCode = str_replace("<%%PLINK({$luf})%%>", '<button type="button" class="btn btn-default view_parent" id="' . $ptfc[0] . '_view_parent" title="' . html_attr($Translation['View'] . ' ' . $ptfc[1]) . '"><i class="glyphicon glyphicon-eye-open"></i></button>', $templateCode);
		}

		// if user has insert permission to parent table of a lookup field, put an add new button
		if($pt_perm['insert'] /* && !Request::val('Embedded')*/) {
			$templateCode = str_replace("<%%ADDNEW({$ptfc[0]})%%>", '<button type="button" class="btn btn-default add_new_parent" id="' . $ptfc[0] . '_add_new" title="' . html_attr($Translation['Add New'] . ' ' . $ptfc[1]) . '"><i class="glyphicon glyphicon-plus text-success"></i></button>', $templateCode);
		}
	}

	// process images
	$templateCode = str_replace('<%%UPLOADFILE(whens_id)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(whens_when1)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(whens_when2)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(whens_when3)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(whens_description)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(whens_created)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(whens_updated)%%>', '', $templateCode);

	// process values
	if($hasSelectedId) {
		if( $dvprint) $templateCode = str_replace('<%%VALUE(whens_id)%%>', safe_html($urow['whens_id']), $templateCode);
		if(!$dvprint) $templateCode = str_replace('<%%VALUE(whens_id)%%>', html_attr($row['whens_id']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whens_id)%%>', urlencode($urow['whens_id']), $templateCode);
		if( $dvprint) $templateCode = str_replace('<%%VALUE(whens_when1)%%>', safe_html($urow['whens_when1']), $templateCode);
		if(!$dvprint) $templateCode = str_replace('<%%VALUE(whens_when1)%%>', html_attr($row['whens_when1']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whens_when1)%%>', urlencode($urow['whens_when1']), $templateCode);
		if( $dvprint) $templateCode = str_replace('<%%VALUE(whens_when2)%%>', safe_html($urow['whens_when2']), $templateCode);
		if(!$dvprint) $templateCode = str_replace('<%%VALUE(whens_when2)%%>', html_attr($row['whens_when2']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whens_when2)%%>', urlencode($urow['whens_when2']), $templateCode);
		$templateCode = str_replace('<%%VALUE(whens_when3)%%>', time12(html_attr($row['whens_when3'])), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whens_when3)%%>', urlencode(time12($urow['whens_when3'])), $templateCode);
		$templateCode = str_replace('<%%VALUE(whens_description)%%>', safe_html($urow['whens_description'], $fieldsAreEditable), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whens_description)%%>', urlencode($urow['whens_description']), $templateCode);
		$templateCode = str_replace('<%%VALUE(whens_created)%%>', safe_html($urow['whens_created']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whens_created)%%>', urlencode($urow['whens_created']), $templateCode);
		$templateCode = str_replace('<%%VALUE(whens_updated)%%>', safe_html($urow['whens_updated']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whens_updated)%%>', urlencode($urow['whens_updated']), $templateCode);
	} else {
		$templateCode = str_replace('<%%VALUE(whens_id)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whens_id)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(whens_when1)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whens_when1)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(whens_when2)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whens_when2)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(whens_when3)%%>', time12(''), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whens_when3)%%>', urlencode(time12('')), $templateCode);
		$templateCode = str_replace('<%%VALUE(whens_description)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whens_description)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(whens_created)%%>', '<%%creationTimestamp%%>', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whens_created)%%>', urlencode('<%%creationTimestamp%%>'), $templateCode);
		$templateCode = str_replace('<%%VALUE(whens_updated)%%>', '<%%editingTimestamp%%>', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whens_updated)%%>', urlencode('<%%editingTimestamp%%>'), $templateCode);
	}

	// process translations
	$templateCode = parseTemplate($templateCode);

	// clear scrap
	$templateCode = str_replace('<%%', '<!-- ', $templateCode);
	$templateCode = str_replace('%%>', ' -->', $templateCode);

	// hide links to inaccessible tables
	if(Request::val('dvprint_x') == '') {
		$templateCode .= "\n\n<script>\$j(function() {\n";
		$arrTables = getTableList();
		foreach($arrTables as $name => $caption) {
			$templateCode .= "\t\$j('#{$name}_link').removeClass('hidden');\n";
			$templateCode .= "\t\$j('#xs_{$name}_link').removeClass('hidden');\n";
		}

		$templateCode .= $jsReadOnly;
		$templateCode .= $jsEditable;

		if(!$hasSelectedId) {
		}

		$templateCode.="\n});</script>\n";
	}

	// ajaxed auto-fill fields
	$templateCode .= '<script>';
	$templateCode .= '$j(function() {';


	$templateCode.="});";
	$templateCode.="</script>";
	$templateCode .= $lookups;

	// handle enforced parent values for read-only lookup fields
	$filterField = Request::val('FilterField');
	$filterOperator = Request::val('FilterOperator');
	$filterValue = Request::val('FilterValue');

	// don't include blank images in lightbox gallery
	$templateCode = preg_replace('/blank.gif" data-lightbox=".*?"/', 'blank.gif"', $templateCode);

	// don't display empty email links
	$templateCode=preg_replace('/<a .*?href="mailto:".*?<\/a>/', '', $templateCode);

	/* default field values */
	$rdata = $jdata = get_defaults('whens');
	if($hasSelectedId) {
		$jdata = get_joined_record('whens', $selectedId);
		if($jdata === false) $jdata = get_defaults('whens');
		$rdata = $row;
	}
	$templateCode .= loadView('whens-ajax-cache', ['rdata' => $rdata, 'jdata' => $jdata]);

	// hook: whens_dv
	if(function_exists('whens_dv')) {
		$args = [];
		whens_dv(($hasSelectedId ? $selectedId : FALSE), getMemberInfo(), $templateCode, $args);
	}

	return $templateCode;
}